onClick:
{{
  (function() {

    if (!sel_customer.selectedOptionValue) {
      showAlert('Please select a customer', 'warning');
      return;
    }

    if (!sel_job_type.selectedOptionValue) {
      showAlert('Please select a job type', 'warning');
      return;
    }

    if (!dp_collection_date.selectedDate) {
      showAlert('Please set a collection date', 'warning');
      return;
    }

    qry_collection_create.run(
      function() {
        showAlert('Collection created successfully', 'success');
        navigateTo(
          'CollectionView',
          {
            collectionId: qry_collection_create.data[0]?.collection_id
          },
          'SAME_WINDOW'
        );
      },
      function() {
        showAlert('Failed to create collection', 'error');
      }
    );

  })()
}}
